/**
 * Pixel world map data layer — real-geography raster (worldgrid.json,
 * generated by scripts/build-worldgrid.mjs from Natural Earth data) plus
 * three-direction price coloring vs the baseline region:
 *   baseline (US) = neutral · cheaper = green family · pricier = red family
 * Two intensity steps per direction (light <30% gap, deep ≥30%).
 */
import WORLD_DATA from './worldgrid.data.mjs';

export const WORLD = WORLD_DATA;

export const DEEP_GAP_PCT = 30;

/** pctVsBaseline: negative = cheaper. */
export function directionFor(pctVsBaseline, isBaseline = false) {
  if (isBaseline) return { dir: 'baseline', cls: 'wm-baseline' };
  if (pctVsBaseline == null) return { dir: 'nodata', cls: 'wm-land' };
  if (pctVsBaseline <= -DEEP_GAP_PCT) return { dir: 'cheaper', cls: 'wm-cheaper-2' };
  if (pctVsBaseline < 0) return { dir: 'cheaper', cls: 'wm-cheaper-1' };
  if (pctVsBaseline >= DEEP_GAP_PCT) return { dir: 'pricier', cls: 'wm-pricier-2' };
  if (pctVsBaseline > 0) return { dir: 'pricier', cls: 'wm-pricier-1' };
  return { dir: 'baseline', cls: 'wm-par' };
}

/**
 * Enrich snapshot regions for the map. Baseline defaults to US; when the
 * snapshot has no US row the cheapest region becomes the baseline so the
 * comparison stays meaningful.
 */
export function mapRegions(regions, baselineCc = 'US') {
  const rows = (regions ?? []).filter((r) => WORLD.countries[r.cc]);
  if (rows.length === 0) return { baseline: null, regions: [] };
  const baseline = rows.find((r) => r.cc === baselineCc) ?? [...rows].sort((a, b) => a.usd - b.usd)[0];
  return {
    baseline: baseline.cc,
    regions: rows.map((r) => {
      const isBaseline = r.cc === baseline.cc;
      const pctVsBaseline = isBaseline || !(baseline.usd > 0) ? 0 : Math.round((r.usd / baseline.usd - 1) * 100);
      return {
        cc: r.cc,
        usd: r.usd,
        local: r.amount,
        currency: r.currency,
        pctVsBaseline,
        ...directionFor(pctVsBaseline, isBaseline),
        runs: WORLD.countries[r.cc],
        centroid: WORLD.centroids[r.cc],
      };
    }),
  };
}
